CREATE TABLE IF NOT EXISTS instagram_accounts (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE, platform_account_id TEXT, username TEXT NOT NULL, account_type TEXT NOT NULL CHECK (account_type IN ('business','creator','personal','unknown')), is_connected BOOLEAN NOT NULL DEFAULT false, is_public BOOLEAN NOT NULL DEFAULT true, source_of_truth TEXT NOT NULL CHECK (source_of_truth IN ('meta_api','provider','scrape','mixed')), first_seen_at TIMESTAMPTZ NOT NULL DEFAULT now(), last_seen_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE (tenant_id, username));
